const short layer4_biases[40] = {
    1, 1, 0, 4, 0, -3, 2, -1, -1, 0, -4, -1, 5, 0, 2, 3, 
    2, -3, 0, 3, 0, -4, -2, 4, -2, 1, 2, -1, 0, 1, 1, -2, 
    -1, 0, -2, -3, -4, -1, -2, 1
};


// Main entry point
int main(void) {
#ifndef UNIVAC
    console_setup();
#endif

    ChatState state;
    init_chat(&state);
    run_chat(&state);
    return 0;
}

// Initialize chat state
void init_chat(ChatState* state) {
    memset(state, 0, sizeof(ChatState));
    clear_context(state);
}

// Clear context to initial state (spaces)
void clear_context(ChatState* state) {
    memset(state->context_chars, ' ', CONTEXT_LEN);
    encode_context(state);
}

// Main chat loop
void run_chat(ChatState* state) {
    printf("CHAT /TYPE ! TO EXIT/\n\n");

    while (1) {
        printf("? ");
        fflush(stdout);
        
        // Read input
        if (fgets(state->user_input, sizeof(state->user_input), stdin) == NULL) {
            break;
        }
        
        // Remove newline
        size_t len = strlen(state->user_input);
        if (len > 0 && state->user_input[len - 1] == '\n') {
            state->user_input[len - 1] = '\0';
        }
        
        // Check for empty input
        if (strlen(state->user_input) == 0) {
            continue;
        }
        
        // Check for exit command
        if (state->user_input[0] == '!') {
            break;
        }
        
        // Process and generate response
        process_query(state, state->user_input);
        generate_response(state);
        printf("\n");
    }
}

// Process a query
void process_query(ChatState* state, const char* query) {
    tokenize_query(state, query);
    clear_context(state);
}

// Generate response character by character
void generate_response(ChatState* state) {
    for (int i = 0; i < MAX_OUTPUT_LEN; i++) {
        // Run neural network
        run_inference(state);
        
        // Find best character
        int char_idx = find_argmax(state->output_buf, NUM_CHARS);
        
        // Check for EOS
        if (char_idx == EOS_IDX) {
            break;
        }
        
        // Print character
        char c = charset[char_idx];
        putchar(c);
        fflush(stdout);
        
        // Update context
        update_context(state, c);
    }
}

void run_inference(ChatState* state) {
    layer_forward(layer1_weights, layer1_biases, state->input_buf, state->hidden_a, 256, 256, 1);
    layer_forward(layer2_weights, layer2_biases, state->hidden_a, state->hidden_b, 256, 192, 1);
    layer_forward(layer3_weights, layer3_biases, state->hidden_b, state->hidden_a, 192, 128, 1);
    layer_forward(layer4_weights, layer4_biases, state->hidden_a, state->output_buf, 128, 40, 0);
}

// Inline weight processing macro for maximum speed
#define PROCESS_BYTE(p, in) do { \
    acc += ((p & 3) - 2) * (in)[0] + (((p >> 2) & 3) - 2) * (in)[1] + \
           (((p >> 4) & 3) - 2) * (in)[2] + ((p >> 6) - 2) * (in)[3]; \
} while(0)

// Layer forward pass with 2-bit weight unpacking (optimized)
void layer_forward(const unsigned char* weights, const short* biases,
                   const short* input, short* output,
                   int in_size, int out_size, int apply_relu) {
    register int o, i;
    int bytes_per_output = in_size >> 2;
    const unsigned char* w_base = weights;

    for (o = 0; o < out_size; o++) {
        register int acc = biases[o];
        const unsigned char* w_ptr = w_base;
        const short* in_ptr = input;

        for (i = bytes_per_output; i > 0; i--) {
            register unsigned int p = *w_ptr++;
            PROCESS_BYTE(p, in_ptr);
            in_ptr += 4;
        }
        w_base += bytes_per_output;

        if (acc > 32767) acc -= 65536;
        if (acc < -32768) acc += 65536;
        acc >>= 2;
        if (apply_relu && acc < 0) acc = 0;
        output[o] = (short)acc;
    }
}

// Multiply-accumulate helper
short muladd(short acc, signed char weight, short activation) {
    int result = (int)acc + (int)weight * (int)activation;
    // Simulate 16-bit overflow
    if (result > 32767) result -= 65536;
    if (result < -32768) result += 65536;
    return (short)result;
}

// Tokenize query into first 128 buckets
void tokenize_query(ChatState* state, const char* query) {
    // Clear query buckets
    memset(state->input_buf, 0, NUM_QUERY_BUCKETS * sizeof(short));
    
    // Make lowercase copy for hashing
    char lower[MAX_INPUT_LEN];
    SAFE_STRCPY(lower, query, sizeof(lower));
    to_lowercase(lower);
    
    // Add boundary spaces
    char padded[MAX_INPUT_LEN + 4];
    snprintf(padded, sizeof(padded), " %s ", lower);
    
    // Extract trigrams
    int len = (int)strlen(padded);
    for (int i = 0; i < len - 2; i++) {
        int bucket = hash_trigram(&padded[i]) & 127;
        state->input_buf[bucket] += ACTIVATION_SCALE;  // Add 32 per trigram
    }
}

// Encode context characters into context buckets
void encode_context(ChatState* state) {
    // Clear context buckets (second half of input_buf)
    memset(&state->input_buf[NUM_QUERY_BUCKETS], 0, NUM_CONTEXT_BUCKETS * sizeof(short));
    
    // Make lowercase copy
    char lower[CONTEXT_LEN + 1];
    for (int i = 0; i < CONTEXT_LEN; i++) {
        char c = state->context_chars[i];
        lower[i] = (c >= 'A' && c <= 'Z') ? (c + 32) : c;
    }
    lower[CONTEXT_LEN] = '\0';
    
    // Hash n-grams (1,2,3-grams with position)
    for (int n = 1; n <= 3; n++) {
        for (int pos = 0; pos <= CONTEXT_LEN - n; pos++) {
            int bucket = hash_ngram(&lower[pos], n, pos) & 127;
            state->input_buf[NUM_QUERY_BUCKETS + bucket] += ACTIVATION_SCALE;
        }
    }
}

// Update context with new character
void update_context(ChatState* state, char new_char) {
    // Shift context left
    memmove(state->context_chars, &state->context_chars[1], CONTEXT_LEN - 1);
    
    // Add new character
    state->context_chars[CONTEXT_LEN - 1] = new_char;
    
    // Re-encode context
    encode_context(state);
}

// Find index of maximum value
int find_argmax(const short* buf, int size) {
    int max_idx = 0;
    short max_val = buf[0];
    
    for (int i = 1; i < size; i++) {
        if (buf[i] > max_val) {
            max_val = buf[i];
            max_idx = i;
        }
    }
    
    return max_idx;
}

// Convert string to lowercase
void to_lowercase(char* str) {
    while (*str) {
        if (*str >= 'A' && *str <= 'Z') {
            *str += 32;
        }
        str++;
    }
}

// Hash a trigram to bucket index
int hash_trigram(const char* trigram) {
    int h = 0;
    for (int i = 0; i < 3; i++) {
        h = (h * 31 + (unsigned char)trigram[i]) & 0xFFFF;
    }
    return h & 127;
}

// Hash an n-gram with position offset
int hash_ngram(const char* ngram, int len, int offset) {
    int h = offset * 7;
    for (int i = 0; i < len; i++) {
        h = (h * 31 + (unsigned char)ngram[i]) & 0xFFFF;
    }
    return h & 127;
}

// Platform-specific console setup
#ifndef UNIVAC
void console_setup(void) {
#ifdef _WIN32
    // Set console to UTF-8 for better text handling
    SetConsoleOutputCP(65001);
    SetConsoleCP(65001);
#endif
}
#endif
